ll dfs(ll now, ll from){

  ll res = 1;

  for(ll to : E[now]){

    if(to == from) continue;

    res *= (dfs(to, now) + 1);

    res %= M;

  }

  return D[now] = res;

}



void dfsPar(ll now, ll from){

  ans[now] = (D[now] + D[now] * Par[now]) % M;

  vector<ll> sekiPre(E[now].size() + 1);

  sekiPre[0] = 1;

  rep(i, E[now].size()){

    if(E[now][i] == from) sekiPre[i+1] = sekiPre[i];

    else sekiPre[i+1] = sekiPre[i] * (D[E[now][i]]+1) % M;

  }

  vector<ll> sekiSuf(E[now].size() + 1);

  sekiSuf[E[now].size()] = 1;

  revrep(i, E[now].size()){

    if(E[now][i] == from) sekiSuf[i] = sekiSuf[i+1];

    else sekiSuf[i] = sekiSuf[i+1] * (D[E[now][i]]+1) % M;

  }



  rep(i, E[now].size()){

    ll to = E[now][i];

    if(to == from) continue;

    Par[to] = (1 + Par[now]) * sekiPre[i] % M * sekiSuf[i+1] % M;

    dfsPar(to, now);

  }

}



void solve(){

  dfs(0, -1);

  dfsPar(0, -1);

  rep(i, N){

    cout << ans[i] << endl;

  }

}



